SELECT LettureTXT_UPC.EANCODELETTORETXT, [Item Cross Reference].[Cross-Reference No_] AS [EAN\UPC], Item.[Product Family] AS Famiy, Item.[Trademark Code] AS Brand_, Item_1.[Season Code], Item.[CARRY OVER], Item.[Product Sex] AS Gender, Item_1.Description, Item_1.No_ AS Model, Item_1.[Description 2], Item.No_ AS Article, UPCCodes_CleanDoubled.Multiplo, 1 AS Quantity, Item.[Variable Code 01] AS Color, Item.[Variable Code 02] AS [Size], Item.[Tariff No_] AS [Intrastat Code], Item.[Country_Region of Origin Code] AS [Country of Origin Code], LettureTXT_UPC.CARTONE AS [Box Number], Item.[Collection Code]
FROM (LettureTXT_UPC LEFT JOIN UPCCodes_CleanDoubled ON LettureTXT_UPC.EANCODELETTORETXT = UPCCodes_CleanDoubled.[Cross-Reference No_]) LEFT JOIN (([Item Cross Reference] LEFT JOIN Item ON [Item Cross Reference].[Item No_] = Item.No_) LEFT JOIN Item AS Item_1 ON Item.[Model Item No_] = Item_1.No_) ON (UPCCodes_CleanDoubled.[MaxDiItem No_] = [Item Cross Reference].[Item No_]) AND (UPCCodes_CleanDoubled.[Cross-Reference No_] = [Item Cross Reference].[Cross-Reference No_]);

